import React from 'react';
import { observer, inject, useLocalStore, useObserver } from 'mobx-react';
import { errBoundary } from '@/components/ErrorBoundary';
import BackBtn from '@/components/BackBtn';
import { EditTableRow, EditTableCell } from '@/components/EditTable';
import { Table, Radio, Select } from 'antd';
import TargetSettingStore, {
    enum_target_type,
    IRegionItem,
    ITargetItem,
    ITargetParams,
    ITargetSettingParams,
    initTargetItem
} from '@/store/TargetSetting/typing';
import { TARGET_TYPE_LIST } from './constant';
import {} from '@/utils/method';
import {} from '@/utils/constant';
import styles from './index.less';

const { Option } = Select;

interface IProps {
    targetSettingStore: TargetSettingStore;
}

interface IState {
    selectedYear: string; // 年
    isTargetLoading: boolean; // 表格加载中
    regionList: IRegionItem[];
    targetList: ITargetItem[];
}

@inject('targetSettingStore')
@observer
class TargetSetting extends React.Component<IProps, IState> {
    constructor(props: IProps) {
        super(props);
        this.state = {
            selectedYear: '2020',
            isTargetLoading: false,
            regionList: [],
            targetList: []
        };
    }
    componentDidMount() {
        this.initData();
    }
    /**
     * 数据加载
     * @return {void}
     */
    initData = async () => {
        const _this = this;
        const { getFactoryRegionList } = this.props.targetSettingStore;
        _this.setState({
            isTargetLoading: true
        });
        const { data } = await getFactoryRegionList();
        if (data && data.length > 0) {
            _this.setState(
                {
                    regionList: data
                },
                _this.getTargetList
            );
        } else {
            _this.setState({
                isTargetLoading: false
            });
        }
    };
    getTargetList = async (params?: ITargetParams) => {
        const _this = this;
        _this.setState({
            isTargetLoading: true
        });
        const { regionList, selectedYear } = _this.state;
        const { targetSettingStore } = _this.props;
        const { selectedTargetType, getTargetList } = targetSettingStore;
        const { data }: { data: ITargetItem[] } = await getTargetList({
            f_type: selectedTargetType,
            f_year: selectedYear,
            ...params
        });
        if (data) {
            const newData: ITargetItem[] = regionList.map(regionItem => {
                const findData = data.find(targetItem => targetItem.f_province_id === regionItem.f_province_id);
                return {
                    ...findData,
                    f_province_id: regionItem.f_province_id,
                    f_province: regionItem.f_province
                };
            });
            _this.setState({
                targetList: newData
            });
        }
        _this.setState({
            isTargetLoading: false
        });
    };
    changeTargetType = event => {
        const { value } = event.target;
        const { changeTargetType } = this.props.targetSettingStore;
        changeTargetType(value);
        this.getTargetList();
    };
    yearChange = value => {
        this.setState({ selectedYear: value }, this.getTargetList);
    };
    handleSave = async row => {
        const { selectedYear, targetList } = this.state;
        const { selectedTargetType, setTargetList } = this.props.targetSettingStore;
        const findData = targetList.find(item => row.f_province_id === item.f_province_id);
        if (!findData) return;
        const keys = Object.keys(row);
        for (let i = 0; i < keys.length; i++) {
            const currentKeyName = keys[i];
            if (row[currentKeyName] !== findData[currentKeyName]) {
                await setTargetList({
                    ...row,
                    f_type: selectedTargetType,
                    f_year: selectedYear
                });
                this.getTargetList();
                return;
            }
        }
    };

    render() {
        const _this = this;
        const { isTargetLoading, targetList, selectedYear } = _this.state;
        const { selectedTargetType } = _this.props.targetSettingStore;
        const columnsOrigin = [
            {
                title: '大区',
                dataIndex: 'f_province',
                width: 100,
                fixed: 'left'
            },
            {
                title: '1月',
                dataIndex: 'f_january'
            },
            {
                title: '2月',
                dataIndex: 'f_february'
            },
            {
                title: '3月',
                dataIndex: 'f_march'
            },
            {
                title: '4月',
                dataIndex: 'f_april'
            },
            {
                title: '5月',
                dataIndex: 'f_may'
            },
            {
                title: '6月',
                dataIndex: 'f_june'
            },
            {
                title: '7月',
                dataIndex: 'f_july'
            },
            {
                title: '8月',
                dataIndex: 'f_august'
            },
            {
                title: '9月',
                dataIndex: 'f_september'
            },
            {
                title: '10月',
                dataIndex: 'f_octover'
            },
            {
                title: '11月',
                dataIndex: 'f_noveber'
            },
            {
                title: '12月',
                dataIndex: 'f_december'
            }
        ];
        const components = {
            body: {
                row: EditTableRow,
                cell: EditTableCell
            }
        };
        const columns = columnsOrigin.map(col => {
            return {
                ...col,
                align: 'center',
                render: value => {
                    if (!value) return '-';
                    else {
                        return `${value}${
                            selectedTargetType !== enum_target_type.profit && col.dataIndex !== 'f_province' ? '%' : ''
                        }`;
                    }
                },
                onCell: record => {
                    return {
                        record,
                        editable: col.dataIndex !== 'f_province' ? true : false,
                        dataIndex: col.dataIndex,
                        handleSave: this.handleSave
                    };
                }
            };
        });
        return (
            <div id="page-target-setting" className={styles.pageTargetSetting}>
                <div className={styles.header}>
                    <BackBtn className={styles.backBtn} />
                    <div className={styles.line} />
                    <div className={styles.headerTitle}>区域目标</div>
                </div>
                <div className={styles.selectorHeader}>
                    <div className={styles.yearSelector}>
                        <Select
                            onChange={_this.yearChange}
                            value={selectedYear}
                            defaultValue={selectedYear}
                            style={{ width: 90 }}
                            bordered={false}
                        >
                            <Option value="2020">2020</Option>
                            <Option value="2019">2019</Option>
                            <Option value="2018">2018</Option>
                        </Select>
                    </div>
                    <div className={styles.line} />
                    <div className={styles.headerMiddle}>
                        {TARGET_TYPE_LIST.map((targetTypeItem, index) => (
                            <Radio.Group
                                key={index}
                                defaultValue={-1}
                                value={selectedTargetType}
                                onChange={_this.changeTargetType}
                                className="middleBtnSingle"
                                buttonStyle="solid"
                            >
                                <Radio.Button key={targetTypeItem.value} value={targetTypeItem.value}>
                                    {targetTypeItem.title}
                                </Radio.Button>
                            </Radio.Group>
                        ))}
                    </div>
                </div>
                <div className={styles.container}>
                    <Table
                        rowKey="f_province_id"
                        loading={isTargetLoading}
                        components={components}
                        columns={columns}
                        scroll={{ x: 1300 }}
                        rowClassName={() => 'editable-row'}
                        dataSource={targetList}
                        pagination={false}
                        locale={{
                            emptyText: '暂无站点'
                        }}
                    />
                </div>
            </div>
        );
    }
}

export default errBoundary(TargetSetting);
