import React, { useState, useEffect, useContext, useRef } from 'react';
import { Input, Form } from 'antd';
import styles from './index.less';

const EditableContext = React.createContext<any>(null);

interface Item {
    key: string;
    name: string;
    age: string;
    address: string;
}

interface EditableCellProps {
    editable: boolean; // 单元格是否可编辑
    children: React.ReactNode; // 单元格子节点
    dataIndex: string; // column key
    record: Item; // 单元格源数据
    handleSave: (record: Item) => void; // 单元格失去焦点的处理
}

// 自定义table的 行
export const EditTableRow: React.FC = props => {
    const [form] = Form.useForm();
    return (
        <Form form={form} component={false}>
            <EditableContext.Provider value={form}>
                <tr {...props} />
            </EditableContext.Provider>
        </Form>
    );
};

// 自定义table的 单元格
export const EditTableCell: React.FC<EditableCellProps> = props => {
    const { editable, children, dataIndex, record, handleSave, ...restProps } = props;
    const [editing, setEditing] = useState(false);
    const inputRef = useRef();
    const form = useContext(EditableContext);

    useEffect(() => {
        if (editing) {
            inputRef?.current?.focus();
        }
    }, [editing]);
    const toggleEdit = () => {
        setEditing(!editing);
        form.setFieldsValue({ [dataIndex]: record[dataIndex] });
    };
    const blurHandler = async e => {
        try {
            const values = await form.validateFields();

            toggleEdit();
            handleSave({ ...record, ...values });
        } catch (errInfo) {
            console.log('Save failed:', errInfo);
        }
    };

    let childNode = children;
    if (editable) {
        childNode = editing ? (
            <Form.Item style={{ margin: 0 }} name={dataIndex}>
                <Input type="number" ref={inputRef} onBlur={blurHandler} className={styles.inputClass} />
            </Form.Item>
        ) : (
            <div onClick={toggleEdit}>{children}</div>
        );
    }

    return <td {...restProps}>{childNode}</td>;
};
